import{_ as l,o,c as i,ag as d}from"./chunks/framework.BDO_Gsxu.js";const a="/ahxi3/image/cpu-interface.png",c="/ahxi3/image/terminal-ad.png",r="/ahxi3/image/firsttime.png",t="/ahxi3/image/open-linux.png",n="/ahxi3/image/date.png",s="/ahxi3/image/ls-l.png",x=JSON.parse('{"title":"如何使用Bash （Born Again SHell ）","description":"","frontmatter":{},"headers":[],"relativePath":"notes/web.security.md","filePath":"notes/web.security.md"}'),h={name:"notes/web.security.md"};function u(m,e,p,b,g,w){return o(),i("div",null,[...e[0]||(e[0]=[d('<h1 id="如何使用bash-born-again-shell" tabindex="-1">如何使用Bash （<em>B</em>orn <em>A</em>gain <em>SH</em>ell ） <a class="header-anchor" href="#如何使用bash-born-again-shell" aria-label="Permalink to &quot;如何使用Bash （*B*orn *A*gain *SH*ell ）&quot;">​</a></h1><blockquote><p>Q:为什么不直接使用windows的powershell？</p><p>A:powershell和bash的语法不通，而且我现在也只会bash而不会powershell，后续会去学习！</p></blockquote><h2 id="_1-安装wsl" tabindex="-1">1.安装WSL <a class="header-anchor" href="#_1-安装wsl" aria-label="Permalink to &quot;1.安装WSL&quot;">​</a></h2><h3 id="需要安装wsl-windows-subsystem-for-linux-首先需要启动两个设置" tabindex="-1">需要安装WSL（<strong>W</strong>indows <strong>S</strong>ubsystem for <strong>L</strong>inux），首先需要启动两个设置 <a class="header-anchor" href="#需要安装wsl-windows-subsystem-for-linux-首先需要启动两个设置" aria-label="Permalink to &quot;需要安装WSL（**W**indows **S**ubsystem for **L**inux），首先需要启动两个设置&quot;">​</a></h3><ul><li><p>启动虚拟化：</p><ul><li>如何检测：打开任务管理器，找到&quot;<strong>性能</strong>&quot; -&gt; &quot;<strong>cpu面板</strong>&quot;，然后检查虚拟化是否打开。</li></ul><p><img src="'+a+'" alt="cpuinterface" title="cpu-interface"></p><ul><li>若没打开，参考<a href="https://blog.csdn.net/2501_90561511/article/details/145647764" target="_blank" rel="noreferrer">这篇文章</a></li></ul></li><li><p>改动两个设置：</p><ul><li>打开“<strong>控制面板</strong>” -&gt; “<strong>程序</strong>” -&gt; “<strong>启用或关闭Windows功能</strong>”。</li><li>勾选“<strong>适用于Linux的Windows子系统</strong>”与“<strong>虚拟机平台</strong>”，然后点击“<strong>确定</strong>”。</li><li>系统将提示重新启动，完成后WSL功能即已启用。</li></ul></li></ul><h3 id="很好-现在你已经具备了安装wsl的初始条件了-接下来正式安装吧" tabindex="-1">很好，现在你已经具备了安装WSL的初始条件了，接下来正式安装吧 <a class="header-anchor" href="#很好-现在你已经具备了安装wsl的初始条件了-接下来正式安装吧" aria-label="Permalink to &quot;很好，现在你已经具备了安装WSL的初始条件了，接下来正式安装吧&quot;">​</a></h3><ul><li>右键屏幕左下角的windows logo，然后点击“终端管理员”。</li></ul><p><img src="'+c+'" alt="terminal" title="terminal-ad"></p><ul><li>输入以下命令并按enter键：</li></ul><blockquote><p><code>wsl --install --web-download</code> //--web-download是为了提高下载速度</p><p><code>wsl --list --online</code> //列出可下载的linux版本</p><p><code>wsl --install -d kali linux</code> //下载kali linux</p></blockquote><h3 id="第一次完成下载之后会发现要你输入一些东西" tabindex="-1">第一次完成下载之后会发现要你输入一些东西 <a class="header-anchor" href="#第一次完成下载之后会发现要你输入一些东西" aria-label="Permalink to &quot;第一次完成下载之后会发现要你输入一些东西&quot;">​</a></h3><ul><li>用户名：取个好记的名字！</li><li>输入密码：好记！</li><li>再次输入密码：好记好记！</li></ul><blockquote><p>如果你像我一样，输入的时候没看到自己输入的什么，别担心，这是正常的，其实你已经输入了，只需要继续输入就可以</p></blockquote><ul><li>下载完成后重启电脑，如果你可以在这个地方找到像我一样的<strong>kali-linux</strong>，那么恭喜你，成功安装了WSL！</li></ul><p><img src="'+r+'" alt="kali-linux" title="first-time"></p><h2 id="_2-各种命令的用法" tabindex="-1">2.各种命令的用法 <a class="header-anchor" href="#_2-各种命令的用法" aria-label="Permalink to &quot;2.各种命令的用法&quot;">​</a></h2><p>Well done, bro，接下来使用Bash做一些有趣的事情吧</p><h3 id="首先-打开shell后-打开你的kali-linux-或者其他的linux-比如ubuntu也可以" tabindex="-1">首先，打开shell后，打开你的kali-linux（或者其他的linux，比如ubuntu也可以） <a class="header-anchor" href="#首先-打开shell后-打开你的kali-linux-或者其他的linux-比如ubuntu也可以" aria-label="Permalink to &quot;首先，打开shell后，打开你的kali-linux（或者其他的linux，比如ubuntu也可以）&quot;">​</a></h3><ul><li>如果你成功完成了操作，应该可以看到类似画面👇</li></ul><p><img src="'+t+'" alt="linux" title="open-linux"></p><ul><li>键入 <code>data</code></li><li>wow，居然显示出了今天的日期与时间，cool</li></ul><p><img src="'+n+'" alt="date" title="date"></p><h3 id="恭喜你完成了你的第一步操作" tabindex="-1">恭喜你完成了你的第一步操作！ <a class="header-anchor" href="#恭喜你完成了你的第一步操作" aria-label="Permalink to &quot;恭喜你完成了你的第一步操作！&quot;">​</a></h3><blockquote><p>接下来开始正式学习吧😀</p></blockquote><h4 id="echo命令-类似print-printf" tabindex="-1">echo命令（类似print/printf） <a class="header-anchor" href="#echo命令-类似print-printf" aria-label="Permalink to &quot;echo命令（类似print/printf）&quot;">​</a></h4><ul><li>输入<code>echo hello</code></li><li>得到输出<code>hello</code></li><li>输入<code>echo hello world</code></li><li>得到输出<code>hello world</code></li></ul><blockquote><p>但在使用mkdir hello world时，会产生hello和world两个文件夹，如果想要生成一个叫hello world的文件夹，需要用双引号或单引号，如mkdir &quot;hello world&quot;，之后会进行详细介绍</p></blockquote><hr><p>现在你可能会有疑问，“shell是如何知道这些指令是如何运行的？”，答案是在计算机内储存着一些内置程序，shell通过访问这些程序来知道你要做什么，而shell则是通过计算机中的<strong>PATH</strong>来寻找可执行的程序的</p><ul><li>现在，键入<code>echo $PATH</code></li><li>得到了一大堆看不懂的输出😵</li><li>但现在在左下角的搜索栏中搜索<em>环境变量</em>，进入<em>编辑系统环境变量</em>，在窗口内点击<em>环境变量</em></li><li>在系统变量栏中找到<em>Path</em>，双击</li><li>🤔这些好像就是刚刚输入<code>echo $PATH</code>之后的各种路径？</li></ul><p>没错！聪明的你肯定已经想到了，系统正是通过这些路径来访问可执行的内置程序的！</p><ul><li>比如，键入 <code>which echo</code></li><li>输出 <code>/usr/bin/echo</code>，这就是echo语句的<strong>绝对</strong>查询路径</li></ul><h4 id="pwd命令-present-working-directory-目前工作目录" tabindex="-1">pwd命令(<em>P</em>resent <em>W</em>orking <em>D</em>irectory，目前工作目录) <a class="header-anchor" href="#pwd命令-present-working-directory-目前工作目录" aria-label="Permalink to &quot;pwd命令(*P*resent *W*orking *D*irectory，目前工作目录)&quot;">​</a></h4><p>那么问题来了，“明明在windows下，一个路径的开头都有C:\\或者D:\\这样的开头，为什么linux下的路径没有呢？”🤔</p><p>答案是，linux下，所有的路径都属于同一个命名空间，用一个不大恰当的比喻就是，linux只有一个硬盘，只能在这一个盘内进行查询，也就没必要区分C盘D盘了🥸👆</p><p>而相对路径和绝对路径正是在这个概念下产生的，<strong>相对</strong>代表着这个路径与你现在所在地方的距离，而<strong>绝对</strong>代表这个路径与根目录的距离</p><ul><li>键入<code>pwd</code></li><li>得到 <code>/home/Ahxi3</code></li><li><code>/home/Ahxi3</code>即为目前工作目录的绝对路径</li></ul><hr><ul><li>又如刚刚的<code>/usr/bin/echo</code>就是绝对路径</li><li>而如果你使用 <code>cd /usr</code>，则此时你所在位置为<code>/usr</code>，此时的<code>/bin/echo</code>就是相对路径</li></ul><h4 id="cd命令-change-directory-更改当前工作目录" tabindex="-1">cd命令，(<em>C</em>hange <em>D</em>irectory，更改当前工作目录) <a class="header-anchor" href="#cd命令-change-directory-更改当前工作目录" aria-label="Permalink to &quot;cd命令，(*C*hange *D*irectory，更改当前工作目录)&quot;">​</a></h4><ul><li>可以试着键入<code>cd /home</code>，此时的工作目录就切换到了<code>/home</code></li><li>此时输入<code>pwd</code>，就会输出<code>/home</code></li><li>有四个较为特殊的目录形式，<code>.</code>（表示当前目录），<code>..</code>（表示当前父目录）</li><li><code>~</code>（表示默认路径），<code>-</code>（表示上一次切换前的路径）</li><li>如键入<code>cd .</code>，则会改动当前工作目录到当前目录（没变）</li><li>键入<code>cd ..</code>，则改动当前工作目录到当前父目录（可以看到当前工作目录变为<code>/</code>）</li><li>此时再键入<code>cd ./home</code>，可以看到当前工作目录由<code>/</code>变成了<code>/home</code></li><li>键入<code>cd ~</code>，则改动当前目录到默认目录</li><li>此时键入<code>cd -</code>，则回到上次切换前的路径，即<code>/home</code></li></ul><h4 id="ls命令-list-列出当前工作目录中的所有文件" tabindex="-1">ls命令(<em>L</em>i<em>S</em>t，列出当前工作目录中的所有文件) <a class="header-anchor" href="#ls命令-list-列出当前工作目录中的所有文件" aria-label="Permalink to &quot;ls命令(*L*i*S*t，列出当前工作目录中的所有文件)&quot;">​</a></h4><ul><li>键入<code>cd /</code></li><li>经过上一步操作，我们现在处于根路径<code>/</code>下，此时键入<code>ls</code></li><li>得到根路径下所有文件名称</li><li><code>ls</code>也可以在之后加上路径，如<code>ls ./home</code>，就会展示当前目录中，home文件内的东西</li></ul><hr><p>你可以在任何命令后加上<code>--help</code>，如</p><ul><li>键入<code>ls -help</code></li><li>跳出来了一堆看不懂的东西😵</li><li>但这些看不懂的东西其实是关于<code>ls</code>这个命令的所有用法</li><li>如<code>ls -l</code>，这个指令会展示出当前目录下所有文件的附加信息👇</li></ul><p><img src="'+s+'" alt="ls-l-home" title="ls-l-home"></p><p>里面有很多看不懂的列，没关系，我们一个个来解读</p><ul><li>第一列，是用来定义文件类型以及不同用户的访问权限的 <ul><li>首字母： <ul><li><code>-</code>普通文件</li><li><code>d</code>目录</li><li><code>l</code>符号链接（软连接）</li><li>还有一些其他的不太常见，感兴趣的可自己了解</li></ul></li><li>2-4字符：文件所有者的权限（r读，w写，x执行，-无权限）</li><li>5-7字符：文件所属组的权限</li><li>8-10字符：其他用户的权限</li></ul></li><li>第二列：硬连接数（有几个文件名在访问这个文件）</li><li>第三列：文件拥有者（用户名）</li><li>第四列：文件所属组（组名）</li><li>第五列：文件大小（字节数）</li><li>第六，七，八列：最后修改时间</li><li>第九列：文件名 <ul><li>对于符号连接，还会显示-&gt;指向的目标文件（实际访问的文件）</li></ul></li></ul><h4 id="mv命令-move-把一个文件移到另一个地方" tabindex="-1">mv命令（<em>M</em>o<em>V</em>e，把一个文件移到另一个地方） <a class="header-anchor" href="#mv命令-move-把一个文件移到另一个地方" aria-label="Permalink to &quot;mv命令（*M*o*V*e，把一个文件移到另一个地方）&quot;">​</a></h4><ul><li>键入<code>mv hello.md world.md</code>，意义是把当前文件夹下的<code>hello.md</code>文件移动到当前文件夹内，并重命名为<code>world.md</code>，直观上看就是把一个文件重命名了</li><li>键入<code>mv world.md ~/download/abc.md</code>，意义是把当前文件夹下的<code>world.md</code>移动到默认路径下的<code>/download</code>目录内，并重命名为<code>abc.md</code></li></ul><h4 id="cp命令-copy-把一个文件复制到另一个地方" tabindex="-1">cp命令（<em>C</em>o<em>P</em>y，把一个文件复制到另一个地方） <a class="header-anchor" href="#cp命令-copy-把一个文件复制到另一个地方" aria-label="Permalink to &quot;cp命令（*C*o*P*y，把一个文件复制到另一个地方）&quot;">​</a></h4><ul><li>键入<code>cp aaa.md ../abc.md</code>，意义是把当前文件夹下的<code>aaa.md</code>复制到父目录中内，并改名为<code>abc.md</code>，与<code>mv</code>的区别在于不删除原文件</li></ul><h4 id="rm命令-remove-把一个文件删除" tabindex="-1">rm命令（<em>R</em>e<em>M</em>ove，把一个文件删除） <a class="header-anchor" href="#rm命令-remove-把一个文件删除" aria-label="Permalink to &quot;rm命令（*R*e*M*ove，把一个文件删除）&quot;">​</a></h4><ul><li>键入<code>rm ../abc.md</code>，意义是把父目录中的<code>abc.md</code>文件删除</li></ul><blockquote><p>需要注意的是，单纯的rm命令并不能删除目录，需要使用rm -r递归地删除（暂时不会）</p><p>可以使用<code>rmdir</code>命令来删除空目录，这是一种安全机制，防止你不小心删了一堆东西</p></blockquote><h4 id="mkdir命令" tabindex="-1">mkdir命令 <a class="header-anchor" href="#mkdir命令" aria-label="Permalink to &quot;mkdir命令&quot;">​</a></h4><ul><li>键入<code>mkdir &quot;my photo&quot;</code>，即在本目录下创建一个名为<code>my photo</code>的文件夹</li></ul><p>未完....</p>',59)])])}const k=l(h,[["render",u]]);export{x as __pageData,k as default};
